        initEnergyChart() {
            const chartDom = this.$refs.energyChart
            const myChart = markRaw(echarts.init(chartDom))
            const option = this.energyChartOption
            myChart.setOption(option)

            // 响应式调整
            window.addEventListener('resize', () => {
                myChart.resize()
            })
        },
        initQualityChart() {
            const chartDom = this.$refs.qualityChart
            const myChart = markRaw(echarts.init(chartDom))
            const option = this.qualityChartOption
            myChart.setOption(option)

            // 添加发光效果动画
            let currentValue = 85
            let direction = 1
            setInterval(() => {
                currentValue += direction * 0.1
                if (currentValue >= 85.5 || currentValue <= 84.5) {
                    direction *= -1
                }
                option.series.forEach(s => {
                    s.data[0].value = currentValue
                })
                myChart.setOption(option)
            }, 100)

            window.addEventListener('resize', () => {
                myChart.resize()
            })
        },

